import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
  HiHome, 
  HiOutlineClipboardList, 
  HiOutlineCalendar, 
  HiOutlineUser, 
  HiOutlineCog 
} from 'react-icons/hi';

const BottomNavigation = () => {
  const { t } = useTranslation();
  const location = useLocation();

  const navItems = [
    { path: '/', label: t('home'), icon: HiHome },
    { path: '/medicines', label: t('medicines'), icon: HiOutlineClipboardList },
    { path: '/availability', label: t('availability'), icon: HiOutlineCalendar },
    { path: '/profile', label: t('profile'), icon: HiOutlineUser },
    { path: '/settings', label: t('settings'), icon: HiOutlineCog }
  ];

  return (
    <nav 
      className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 shadow-lg z-[9999]"
      style={{
        position: 'fixed',
        bottom: 0,
        left: 0,
        right: 0,
        zIndex: 9999,
        backgroundColor: 'white',
        borderTop: '1px solid #e5e7eb',
        paddingBottom: 'env(safe-area-inset-bottom)'
      }}
      role="navigation"
      aria-label="Main navigation"
    >
      <div className="flex justify-around items-center h-20 px-2 w-full">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = location.pathname === item.path;
          
          return (
            <Link
              key={item.path}
              to={item.path}
              className="flex flex-col items-center justify-center py-3 px-1 no-underline min-w-0 flex-1"
              style={{ 
                textDecoration: 'none',
                minHeight: '48px',
                touchAction: 'manipulation'
              }}
              aria-label={`Navigate to ${item.label}`}
            >
              <Icon className={`text-xl mb-1 ${
                isActive 
                  ? 'text-blue-600' 
                  : 'text-gray-600'
              }`} />
              
              <span className={`text-xs font-medium leading-tight text-center ${
                isActive 
                  ? 'text-blue-600' 
                  : 'text-gray-600'
              }`}>
                {item.label}
              </span>
            </Link>
          );
        })}
      </div>
    </nav>
  );
};

export default BottomNavigation;
